mapper.select:
SELECT id, game_type as gameType, set_name as setName, card_name as cardName, card_number as cardNumber, rarity, language, manufacturer, image_url as imageUrl, description, is_active as isActive, pokemon_id as pokemonId FROM card_master
is_active = true
AND game_type = #{gameType}
AND card_name LIKE CONCAT('%', #{cardName}, '%')
AND set_name LIKE CONCAT('%', #{setName}, '%')
AND card_number = #{cardNumber}
AND rarity = #{rarity}
